@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --sat: env(safe-area-inset-top);
  --sab: env(safe-area-inset-bottom);
  --sal: env(safe-area-inset-left);
  --sar: env(safe-area-inset-right);
}

html, body, #root {
  height: 100%;
  width: 100%;
  margin: 0;
  padding: 0;
  background-color: #f8fafc; /* Slate-50 (Light Mode Background) */
  color: #0f172a; /* Slate-900 (Dark Text) */
  /* Use dynamic viewport height for mobile browsers */
  min-height: 100dvh;
}

/* Safe Area Utilities */
.pt-safe {
  padding-top: var(--sat);
}
.pb-safe {
  padding-bottom: var(--sab);
}
.mt-safe {
  margin-top: var(--sat);
}
.mb-safe {
  margin-bottom: var(--sab);
}

/* 
   YouTube-Style Header Spacing 
   Ensures at least 35px of padding for the status bar, 
   preventing content from being hidden behind the notch 
   even if the browser reports 0px safe area.
*/
.pt-safe-header {
  padding-top: max(env(safe-area-inset-top), 35px);
}

/* Header offset: Standard header height + Safe Area 
   Removed the large offset versions to force use of tighter padding 
   in components directly.
*/
.pt-safe-offset-2 {
  padding-top: calc(var(--sat) + 0.5rem);
}

/* Ensure fade-in animations work */
.animate-fade-in {
  animation: fadeIn 0.5s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

/**
 * Automatically manages the Status Bar color (PWA Theme Color) based on the current route.
 * 
 * - All Pages -> Light Background (#ffffff) -> Dark Icons
 */
export const useStatusBar = () => {
  const location = useLocation();

  useEffect(() => {
    // Default to White (Dark Text/Icons) for the entire app now
    let themeColor = '#ffffff'; 

    // Apply the meta tag
    let meta = document.querySelector('meta[name="theme-color"]');
    if (!meta) {
      meta = document.createElement('meta');
      meta.setAttribute('name', 'theme-color');
      document.head.appendChild(meta);
    }
    meta.setAttribute('content', themeColor);

  }, [location]);
};

