import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Clock } from 'lucide-react';
import { useBackHandler } from '../hooks/useBackHandler';

interface TestInterfaceProps {
  questions: Question[];
  subjectName?: string;
  userId: string;
  onComplete: (stats: { correct: number, wrong: number, skipped: number, totalTime: number }) => void;
  onExit: () => void;
  onAnswerSubmit: (qId: number, option: string, isCorrect: boolean, timeTaken: number) => void;
  defaultLanguage?: 'Hindi' | 'English'; 
}

export const TestInterface: React.FC<TestInterfaceProps> = ({ 
    questions, 
    subjectName, 
    userId, 
    onComplete, 
    onExit, 
    onAnswerSubmit,
    defaultLanguage = 'English'
}) => {
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [grid, setGrid] = useState<Record<number, { status: string, answer: string | null }>>({});
  const [timer, setTimer] = useState(0); 
  const [showSolution, setShowSolution] = useState(false);
  const [stats, setStats] = useState({ correct: 0, wrong: 0, answered: 0 });
  const [questionStartTime, setQuestionStartTime] = useState<number>(Date.now());
  const [submitting, setSubmitting] = useState(false);

  // Exit Modal State
  const [showExitModal, setShowExitModal] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Centralized Logic for Back Action
  const handleNavigationBack = () => {
     if (showExitModal) {
         setShowExitModal(false); // Close Modal if open
         return true; 
     }
     if (!submitting) {
         setShowExitModal(true); // Open Modal
         return true;
     }
     return true; // Trap if submitting
  };

  // Sync Hardware Back Button
  useBackHandler(() => {
    return handleNavigationBack();
  }, !submitting); 

  // Initialize Grid
  useEffect(() => {
    const initialGrid: any = {};
    questions.forEach((_, i) => {
        initialGrid[i] = { status: 'not-visited', answer: null };
    });
    if(initialGrid[0]) initialGrid[0].status = 'not-answered';
    setGrid(initialGrid);
    setQuestionStartTime(Date.now()); 
  }, [questions]);

  // Timer
  useEffect(() => {
    const t = setInterval(() => setTimer(time => time + 1), 1000);
    return () => clearInterval(t);
  }, []);

  const currentQ = questions[currentIndex];
  if (!currentQ) return <div className="p-10 text-center flex flex-col items-center justify-center h-screen bg-white text-slate-900"><div className="w-8 h-8 border-4 border-brand-600 border-t-transparent rounded-full animate-spin"></div><p className="mt-4 text-slate-500 font-bold">Loading Test...</p></div>;

  const currentStatus = grid[currentIndex] || { status: 'not-visited', answer: null };

  const handleOptionSelect = (option: string) => {
    if (showSolution) return; 

    const isCorrect = option === currentQ.correct_option;
    const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000); 

    const newGrid = { ...grid };
    newGrid[currentIndex] = {
        answer: option,
        status: isCorrect ? 'answered' : 'not-answered', 
    };
    setGrid(newGrid);
    setShowSolution(true);

    setStats(s => ({
        ...s,
        answered: s.answered + 1,
        correct: isCorrect ? s.correct + 1 : s.correct,
        wrong: !isCorrect ? s.wrong + 1 : s.wrong
    }));

    onAnswerSubmit(currentQ.id, option, isCorrect, timeTaken);
  };

  const finishTest = async () => {
    if (submitting) return;
    setSubmitting(true);

    let correct = 0, wrong = 0, skipped = 0;
    Object.values(grid).forEach((g: any, i) => {
        const q = questions[i];
        if (g.answer) {
            if (g.answer === q.correct_option) correct++;
            else wrong++;
        } else {
            skipped++;
        }
    });

    onComplete({ correct, wrong, skipped, totalTime: timer });
  };

  const handleNext = () => {
    setShowSolution(false);
    if (currentIndex < questions.length - 1) {
      const nextIndex = currentIndex + 1;
      const newGrid = { ...grid };
      if (newGrid[nextIndex].status === 'not-visited') {
          newGrid[nextIndex].status = 'not-answered';
      }
      setGrid(newGrid);
      setCurrentIndex(nextIndex);
      setQuestionStartTime(Date.now());

      // Auto Scroll Palette
      if (scrollRef.current) {
          const itemWidth = 40; 
          const containerWidth = scrollRef.current.clientWidth;
          const scrollPos = (nextIndex * itemWidth) - (containerWidth / 2) + (itemWidth / 2);
          scrollRef.current.scrollTo({ left: scrollPos, behavior: 'smooth' });
      }
    } else {
        finishTest();
    }
  };

  const handlePrev = () => {
      setShowSolution(false);
      if (currentIndex > 0) {
        setCurrentIndex(currentIndex - 1);
        setQuestionStartTime(Date.now());
      }
  }

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getText = (field: string) => {
    const en = currentQ[`${field}_en` as keyof Question] as string;
    const hi = currentQ[`${field}_hi` as keyof Question] as string;
    return lang === 'hi' ? (hi || en) : en;
  };

  const questionsLeft = questions.length - stats.answered;

  return (
    <div className="flex flex-col h-[100dvh] bg-white relative font-sans animate-fade-in overflow-hidden">

        {/* --- HEADER (Fixed with Safe Area) --- */}
        <div className="px-4 pb-3 pt-safe-header bg-white border-b border-slate-100 flex justify-between items-center z-50 sticky top-0 shadow-sm shrink-0">
             <div className="flex items-center gap-3">
                 {/* UI Back Button */}
                 <button onClick={handleNavigationBack} className="text-slate-400 hover:text-slate-800 p-1 -ml-1 rounded-full active:bg-slate-100">
                    <ArrowLeft size={20} />
                 </button>

                 <div className="flex items-center gap-2 bg-slate-50 px-2 py-1 rounded-lg border border-slate-100">
                    <Clock size={14} className="text-slate-500" />
                    <span className="font-mono font-bold text-slate-700 text-sm tracking-wider">{formatTime(timer)}</span>
                 </div>
            </div>

            <div className="text-xs text-slate-500 font-bold uppercase tracking-wider truncate max-w-[120px]">{subjectName || 'Test'}</div>

            <button 
                onClick={finishTest} 
                disabled={submitting}
                className="bg-red-50 text-red-600 px-3 py-1.5 rounded-lg text-[10px] font-bold border border-red-100 hover:bg-red-100 transition-colors disabled:opacity-50 flex items-center gap-2"
            >
                {submitting && <div className="w-3 h-3 border-2 border-red-500 border-t-transparent rounded-full animate-spin"></div>}
                {submitting ? 'Saving...' : 'Submit'}
            </button>
        </div>

        {/* --- LIVE STATS GRID --- */}
        <div className="bg-white border-b border-slate-100 py-2 px-4 flex justify-between items-center text-[10px] font-bold text-slate-500 shrink-0">
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-green-500"></div> {stats.correct} Correct</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div> {stats.wrong} Wrong</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div> {questionsLeft} Left</div>
        </div>

        {/* --- HORIZONTAL PALETTE STRIP --- */}
        <div className="bg-slate-50 border-b border-slate-100 py-3 shrink-0">
            <div ref={scrollRef} className="flex overflow-x-auto px-4 gap-2 hide-scrollbar snap-x scroll-smooth">
                {questions.map((_, i) => {
                    const isCorrect = grid[i]?.answer && grid[i]?.answer === questions[i].correct_option;
                    let bg = 'bg-white text-slate-500 border-slate-200';

                    if (grid[i]?.answer) {
                        if (isCorrect) bg = 'bg-green-600 text-white border-green-600';
                        else bg = 'bg-red-600 text-white border-red-600';
                    } else if (i === currentIndex) {
                        bg = 'ring-1 ring-brand-500 border-brand-500 text-brand-600 bg-brand-50';
                    }

                    return (
                        <div key={i} onClick={() => { 
                            setCurrentIndex(i); 
                            setShowSolution(!!grid[i]?.answer);
                            setQuestionStartTime(Date.now());
                        }} className={`snap-center shrink-0 w-9 h-9 rounded-lg flex items-center justify-center text-xs font-bold border transition-all cursor-pointer relative ${bg}`}>
                            {i + 1}
                        </div>
                    )
                })}
            </div>
        </div>

        {/* --- QUESTION AREA (Scrollable) --- */}
        <div className="flex-1 overflow-y-auto p-5 pb-32 hide-scrollbar w-full">
            <div className="flex justify-between items-start mb-4">
                 <span className="font-bold text-slate-500 text-[10px] uppercase tracking-wider bg-slate-100 px-2 py-1 rounded border border-slate-200">Question {currentIndex + 1}</span>
                 <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-white px-3 py-1 rounded-full border border-slate-200 text-[10px] font-bold text-slate-500 active:scale-95 transition-transform shadow-sm">
                    <i className="fa-solid fa-language"></i> {lang === 'en' ? 'ENG' : 'HIN'}
                </button>
            </div>

            {/* Question Text with Word Break */}
            <p className="text-lg font-bold text-slate-900 leading-relaxed mb-4 font-serif break-words">
                {getText('question_text')}
            </p>

            <div className="flex items-center gap-2 mb-6">
                <span className="bg-green-50 text-green-600 text-[10px] font-bold px-2 py-1 rounded border border-green-100">
                    +1.0
                </span>
                <span className="bg-red-50 text-red-600 text-[10px] font-bold px-2 py-1 rounded border border-red-100">
                    -0.0
                </span>
            </div>

            <div className="space-y-4">
                {['A','B','C','D'].map((opt) => {
                    const optText = getText(`option_${opt.toLowerCase()}`);
                    const isSelected = currentStatus.answer === opt;
                    const isCorrect = opt === currentQ.correct_option;

                    let cardClass = "p-4 rounded-xl border-2 cursor-pointer flex items-start gap-4 transition-all active:scale-[0.98] ";
                    let circleClass = "w-7 h-7 rounded-full border-2 flex items-center justify-center text-sm font-bold shrink-0 transition-colors mt-0.5 ";

                    if (showSolution) {
                        if(isCorrect) {
                            cardClass += "border-green-500 bg-green-50";
                            circleClass += "bg-green-500 text-white border-green-500";
                        } else if (isSelected && !isCorrect) {
                            cardClass += "border-red-500 bg-red-50";
                            circleClass += "bg-red-500 text-white border-red-500";
                        } else {
                            cardClass += "border-slate-100 opacity-50";
                            circleClass += "border-slate-200 text-slate-400";
                        }
                    } else {
                        cardClass += "border-slate-200 bg-white hover:border-brand-300";
                        circleClass += "border-slate-200 text-slate-400 bg-slate-50";
                    }

                    return (
                        <div key={opt} onClick={() => handleOptionSelect(opt)} className={cardClass}>
                            <div className={circleClass}>{opt}</div>
                            <div className="flex-1 text-sm font-medium text-slate-700 break-words leading-relaxed">
                                {optText}
                            </div>
                        </div>
                    )
                })}
            </div>

            {showSolution && (
                <div className="mt-6 p-5 rounded-xl bg-blue-50 border border-blue-100 animate-slide-up">
                    <div className="flex items-center gap-2 mb-2">
                        <i className="fa-solid fa-lightbulb text-blue-500"></i>
                        <p className="text-xs font-bold text-blue-600 uppercase">Explanation</p>
                    </div>
                    <p className="text-sm text-slate-600 leading-relaxed break-words">{getText('solution_short') || "No detailed explanation available for this question."}</p>
                </div>
            )}
        </div>

        {/* --- BOTTOM BAR (Fixed & Safe Area) --- */}
        <div className="absolute bottom-0 w-full bg-white border-t border-slate-100 p-4 pb-safe shadow-[0_-5px_20px_rgba(0,0,0,0.05)] z-30 flex items-center gap-4">
            <div className="w-full flex gap-4 pb-2">
                <button onClick={handlePrev} disabled={currentIndex === 0} className="w-1/3 py-3.5 rounded-xl font-bold text-slate-500 bg-slate-50 border border-slate-200 disabled:opacity-50 hover:bg-slate-100 transition-colors">
                    Previous
                </button>

                <button onClick={handleNext} className="flex-1 bg-brand-600 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-brand-200 hover:bg-brand-700 transition-colors flex items-center justify-center gap-2 active:scale-[0.98]">
                    {currentIndex === questions.length - 1 ? 'Finish' : 'Save & Next'}
                </button>
            </div>
        </div>

        {/* --- EXIT CONFIRMATION MODAL --- */}
        <AnimatePresence>
          {showExitModal && (
              <>
                <motion.div 
                    initial={{ opacity: 0 }} animate={{ opacity: 0.5 }} exit={{ opacity: 0 }}
                    onClick={() => setShowExitModal(false)}
                    className="fixed inset-0 bg-black z-40"
                />
                <motion.div
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 300 }}
                    className="fixed bottom-0 left-0 right-0 bg-white rounded-t-[2rem] z-50 p-6 pb-safe shadow-2xl border-t border-slate-100"
                >
                    <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-6 mt-2"></div>

                    <div className="flex flex-col items-center text-center mb-8">
                        <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mb-4">
                            <i className="fa-solid fa-arrow-right-from-bracket text-2xl text-red-500"></i>
                        </div>
                        <p className="text-slate-900 font-bold text-lg">Exit Test?</p>
                        <p className="text-slate-500 text-sm mt-1 max-w-xs leading-relaxed">
                            Your current progress will be lost if you exit without submitting.
                        </p>
                    </div>

                    <div className="flex gap-4 pb-4">
                        <button 
                            onClick={onExit} 
                            className="flex-1 py-3.5 rounded-xl border border-slate-200 text-slate-600 font-bold hover:bg-slate-50 transition-colors"
                        >
                            Exit
                        </button>
                        <button 
                            onClick={() => setShowExitModal(false)} 
                            className="flex-1 py-3.5 rounded-xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-200 hover:bg-brand-700 transition-colors"
                        >
                            Continue
                        </button>
                    </div>
                </motion.div>
              </>
          )}
      </AnimatePresence>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Question } from '../types';
import { api } from '../services/api';

interface ShortsScreenProps {
  profile: any;
  session: any;
  navigate: (path: string) => void;
  onInteractionSubmit: (questionId: number, isCorrect: boolean, isLiked: boolean, timeSpentSeconds: number) => Promise<void>;
}

export const ShortsScreen: React.FC<ShortsScreenProps> = ({ profile, session, navigate, onInteractionSubmit }) => {
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [loading, setLoading] = useState(true);
  const [questionStartTime, setQuestionStartTime] = useState<number>(Date.now());

  // Function to load a new question
  const loadNewQuestion = async () => {
    setLoading(true);
    const question = await api.getRandomQuestion();
    setCurrentQuestion(question);
    setLoading(false);
    setQuestionStartTime(Date.now());
  };

  useEffect(() => {
    loadNewQuestion();
  }, []);

  const handleSwipe = async (isLiked: boolean) => {
    if (!currentQuestion) return;

    const timeSpentSeconds = Math.floor((Date.now() - questionStartTime) / 1000);
    const isCorrect = false; 

    await onInteractionSubmit(currentQuestion.id, isCorrect, isLiked, timeSpentSeconds);

    // Load next question
    await loadNewQuestion();
  };

  if (loading) {
    return (
      <div className="h-full flex items-center justify-center bg-white">
        <div className="w-8 h-8 border-2 border-brand-600 rounded-full animate-spin border-t-transparent"></div>
      </div>
    );
  }

  if (!currentQuestion) {
    return (
      <div className="h-full flex flex-col items-center justify-center p-6 bg-white">
        <p className="text-slate-400 text-center">No questions available</p>
        <button 
          onClick={() => navigate('/')} 
          className="mt-4 bg-brand-600 text-white px-6 py-2 rounded-xl font-bold"
        >
          Go Home
        </button>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-white text-slate-900">
      {/* Header */}
      <div className="sticky top-0 z-30 px-5 py-3 bg-white flex justify-between items-center border-b border-slate-100 shadow-sm">
        <h2 className="text-xl font-black text-slate-900">Shorts</h2>
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-full bg-slate-50 p-0.5 border border-slate-200 cursor-pointer shadow-sm" onClick={() => navigate('/profile')}>
            <img src={profile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session?.user?.email || 'user'}`} className="w-full h-full rounded-full" alt="User" />
          </div>
        </div>
      </div>

      {/* Question Content Area */}
      <div className="flex-1 overflow-y-auto hide-scrollbar p-6 flex flex-col justify-center">
        <div className="max-w-md mx-auto w-full">
          <div className="mb-4">
            <span className="text-xs text-brand-600 bg-brand-50 px-2 py-1 rounded font-bold uppercase tracking-wider border border-brand-100">{currentQuestion.subject}</span>
          </div>

          <p className="text-xl font-bold text-slate-900 mb-6 leading-relaxed">
            {currentQuestion.question_text_en}
          </p>

          {/* Options Display (Static for Shorts view) */}
          <div className="space-y-2 mb-8 opacity-80">
             <div className="p-3 border border-slate-200 rounded-lg text-sm text-slate-600 bg-slate-50">A. {currentQuestion.option_a_en}</div>
             <div className="p-3 border border-slate-200 rounded-lg text-sm text-slate-600 bg-slate-50">B. {currentQuestion.option_b_en}</div>
             <div className="p-3 border border-slate-200 rounded-lg text-sm text-slate-600 bg-slate-50">C. {currentQuestion.option_c_en}</div>
             <div className="p-3 border border-slate-200 rounded-lg text-sm text-slate-600 bg-slate-50">D. {currentQuestion.option_d_en}</div>
          </div>

          {/* Action Buttons */}
          <div className="flex gap-6 justify-center mt-4">
            <button
              onClick={() => handleSwipe(false)}
              className="flex flex-col items-center gap-1 group"
            >
              <div className="w-16 h-16 rounded-full bg-red-50 text-red-500 border border-red-100 flex items-center justify-center group-hover:scale-110 transition-transform shadow-sm">
                <i className="fa-solid fa-xmark text-2xl"></i>
              </div>
              <span className="text-xs font-bold text-slate-500">Skip</span>
            </button>

            <button
              onClick={() => handleSwipe(true)}
              className="flex flex-col items-center gap-1 group"
            >
              <div className="w-16 h-16 rounded-full bg-green-50 text-green-500 border border-green-100 flex items-center justify-center group-hover:scale-110 transition-transform shadow-sm">
                <i className="fa-solid fa-heart text-2xl"></i>
              </div>
              <span className="text-xs font-bold text-slate-500">Like</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Check, FlaskConical, Atom, Calculator, Dna, Languages, BookType, Tablet, PenTool } from 'lucide-react';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface InfinityPracticeModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
  onStartSession: (subject: string, chapters: string[]) => void;
  initialSubject?: string | null;
  onUpdateSubject?: (subject: string | null) => void;
  instantOpen?: boolean;
}

const subjectsList = [
  { name: 'Maths', icon: Calculator, color: 'text-sky-500', bg: 'bg-white', border: 'border-slate-200' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-sky-500', bg: 'bg-white', border: 'border-slate-200' },
  { name: 'Physics', icon: Atom, color: 'text-sky-500', bg: 'bg-white', border: 'border-slate-200' },
  { name: 'Biology', icon: Dna, color: 'text-sky-500', bg: 'bg-white', border: 'border-slate-200' },
  { name: 'Hindi', icon: Languages, color: 'text-sky-500', bg: 'bg-white', border: 'border-slate-200' },
  { name: 'English', icon: BookType, color: 'text-sky-500', bg: 'bg-white', border: 'border-slate-200' },
];

export const InfinityPracticeModal: React.FC<InfinityPracticeModalProps> = ({ 
  isOpen, 
  onClose, 
  userId, 
  onStartSession,
  initialSubject,
  onUpdateSubject,
  instantOpen = false
}) => {
  // We removed local 'step' state. Step is now derived from selectedSubject.
  // If subject is selected -> Step 2. Else -> Step 1.
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject || null);
  const step = selectedSubject ? 2 : 1;

  const [chapters, setChapters] = useState<{ en: string, hi: string, count: number }[]>([]);
  const [selectedChapters, setSelectedChapters] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  // Sync internal state with props (URL params)
  useEffect(() => {
    if (isOpen) {
        setSelectedSubject(initialSubject || null);
        // Reset chapters if going back to step 1
        if (!initialSubject) {
            setSelectedChapters([]);
        }
    }
  }, [isOpen, initialSubject]);

  // Stack Navigation Logic for Hardware Back Button
  const handleAppBack = () => {
    if (step === 2) {
      // Go back to Step 1
      setSelectedSubject(null);
      if (onUpdateSubject) onUpdateSubject(null); // Update URL
      return true; // Trap
    } else {
      // Exit Modal
      onClose(); 
      return true; // Trap
    }
  };

  useBackHandler(handleAppBack, isOpen);

  useEffect(() => {
    if (selectedSubject) {
      setLoading(true);
      api.getChapterStats(selectedSubject).then(data => {
        setChapters(data);
        // Pre-select first 3 for convenience, or empty
        setSelectedChapters(data.slice(0, 3).map(c => c.en));
        setLoading(false);
      });
    }
  }, [selectedSubject]);

  const handleSubjectSelect = (subject: string) => {
    setSelectedSubject(subject);
    if (onUpdateSubject) onUpdateSubject(subject);
  };

  const toggleChapter = (chapterName: string) => {
    setSelectedChapters(prev => 
      prev.includes(chapterName) 
        ? prev.filter(c => c !== chapterName) 
        : [...prev, chapterName]
    );
  };

  const handleStart = async () => {
    if (!selectedSubject) return;
    if (selectedChapters.length < 2) {
        alert("Minimum 2 chapters required to start.");
        return;
    }
    setCreating(true);
    // Simulating API creation delay if needed
    const sessionId = await api.createPracticeSession(userId, selectedSubject, selectedChapters);
    setCreating(false);
    onStartSession(selectedSubject, selectedChapters);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div 
            initial={{ opacity: instantOpen ? 0.5 : 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black z-40"
          />

          <motion.div
            initial={{ x: instantOpen ? 0 : "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            className="fixed inset-y-0 right-0 w-full max-w-md bg-white z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans text-slate-900"
          >
            <div className="bg-white shadow-sm z-20 border-b border-slate-100 shrink-0 sticky top-0">
                <div className="pt-safe-header pb-4 px-5 flex items-center gap-3">
                    <button onClick={handleAppBack} className="text-slate-400 hover:text-slate-800 transition-colors p-1 -ml-2 rounded-full active:bg-slate-100">
                        <ChevronLeft size={28} strokeWidth={2.5} />
                    </button>
                    <h2 className="text-xl font-black text-slate-900 tracking-tight">
                        {step === 1 ? 'Select Subject' : 'Select Chapters'}
                    </h2>
                </div>

                <div className="px-6 pb-6">
                    <div className="flex items-center justify-between text-sm w-full">
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 1 ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-500'}`}>
                                {step > 1 ? <Check size={10} /> : '1'}
                            </div>
                            <span className={`${step >= 1 ? 'text-slate-900 font-bold' : 'text-slate-400 font-medium'}`}>Subject</span>
                        </div>
                        <div className="flex-1 h-[2px] bg-slate-100 mx-3 rounded-full"></div>
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 2 ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-500'}`}>
                                2
                            </div>
                            <span className={`${step >= 2 ? 'text-slate-900 font-bold' : 'text-slate-400 font-medium'}`}>Chapter</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 min-w-0 relative flex flex-col bg-slate-50">
              <div className="absolute inset-0 overflow-y-auto hide-scrollbar pb-safe">

              {step === 1 && (
                <motion.div 
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex flex-col min-h-full"
                >
                    <div className="p-6 space-y-4 z-10 flex-1">
                        {subjectsList.map((sub) => (
                            <div 
                            key={sub.name}
                            onClick={() => handleSubjectSelect(sub.name)}
                            className={`bg-white h-16 rounded-xl flex items-center px-4 cursor-pointer transition-all border border-slate-200 shadow-sm hover:bg-slate-50 active:scale-[0.98]`}
                            >
                            <div className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-100 mr-4 bg-slate-50">
                                <sub.icon size={20} className={sub.color} strokeWidth={1.5} />
                            </div>
                            <div className="h-8 w-[1px] bg-slate-100 mr-4"></div>
                            <span className="font-bold text-slate-700 text-sm tracking-wide">{sub.name}</span>
                            </div>
                        ))}
                    </div>
                </motion.div>
              )}

              {step === 2 && (
                <motion.div 
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: 20 }}
                    className="p-6 pb-24 flex flex-col min-h-full"
                >
                  {selectedChapters.length < 2 && (
                      <div className="mb-4 bg-red-50 border border-red-100 text-red-600 px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 shrink-0">
                          <div className="w-4 h-4 bg-red-100 rounded-full flex items-center justify-center text-red-600">!</div>
                          Minimum 2 chapters required
                      </div>
                  )}

                  <div className="flex justify-between items-center mb-4 shrink-0">
                    <h3 className="font-bold text-slate-900 text-lg">Select Chapters</h3>
                    <span className="bg-slate-200 text-slate-700 px-3 py-1 rounded-full text-xs font-bold">
                      {selectedChapters.length}/{chapters.length}
                    </span>
                  </div>

                  {loading ? (
                    <div className="space-y-3">
                      {[1,2,3,4,5,6].map(i => <div key={i} className="h-16 bg-white rounded-xl border border-slate-200 animate-pulse" />)}
                    </div>
                  ) : (
                    <div className="space-y-3 pb-4">
                      {chapters.map((chap, idx) => {
                        const isSelected = selectedChapters.includes(chap.en);
                        return (
                          <div 
                            key={chap.en}
                            onClick={() => toggleChapter(chap.en)}
                            className={`bg-white p-4 rounded-xl border flex items-center gap-4 cursor-pointer transition-all ${isSelected ? 'border-brand-500 ring-1 ring-brand-500 shadow-sm bg-brand-50' : 'border-slate-200 hover:border-slate-300'}`}
                          >
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs shrink-0 border ${isSelected ? 'bg-brand-100 text-brand-600 border-brand-200' : 'bg-slate-50 text-slate-500 border-slate-100'}`}>
                              {idx + 1}
                            </div>
                            <div className="flex-1">
                              <h4 className={`font-bold text-sm ${isSelected ? 'text-brand-600' : 'text-slate-800'}`}>{chap.en}</h4>
                              {chap.hi && (
                                <p className="text-xs text-slate-500 font-medium mt-0.5">{chap.hi}</p>
                              )}
                              <p className="text-[10px] text-slate-400 font-medium mt-1">{chap.count} Questions</p>
                            </div>
                            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${isSelected ? 'bg-brand-600 border-brand-600 text-white' : 'border-slate-200 bg-slate-50'}`}>
                              {isSelected && <Check size={12} strokeWidth={3} />}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </motion.div>
              )}
              </div>
            </div>

            {step === 2 && (
              <div className="absolute bottom-0 w-full bg-white border-t border-slate-100 p-4 pb-safe flex gap-4 shadow-[0_-5px_20px_rgba(0,0,0,0.05)] z-20">
                <button 
                  onClick={() => handleSubjectSelect('')} 
                  className="flex-1 py-3 rounded-xl font-bold text-slate-500 bg-white border border-slate-200 hover:bg-slate-50 transition-colors"
                >
                  Previous
                </button>
                <button 
                  onClick={handleStart}
                  disabled={selectedChapters.length < 2 || creating}
                  className="flex-1 py-3 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-brand-700 transition-transform active:scale-95"
                >
                  {creating ? 'Creating...' : 'Start'}
                </button>
              </div>
            )}

          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

