                    {/* Header with Safe Area (pt-safe-header) */}
                    <div className="px-5 pb-4 pt-safe-header bg-white/80 backdrop-blur-sm border-b border-slate-100 flex items-center gap-3 sticky top-0 z-50 shadow-sm shrink-0">
                        <button onClick={handleAppBack} className="w-9 h-9 flex items-center justify-center rounded-full bg-slate-50 text-slate-500 hover:bg-slate-100 border border-slate-200 transition-colors -ml-1 active:scale-95">
                            <ChevronLeft size={24} />
                        </button>
                        <h2 className="text-xl font-black text-slate-900 tracking-tight">Practice PYQs</h2>
                    </div>

                    <div className="flex-1 overflow-y-auto p-5 pb-24 z-10 hide-scrollbar pb-safe">

                        {/* Tabs */}
                        <div className="flex bg-slate-100 p-1.5 rounded-2xl mb-8 border border-slate-200 shadow-inner isolate">
                        {(['objective', 'subjective'] as const).map((tab) => {
                            const isActive = activeTab === tab;
                            return (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
