                                <h3 className="text-xl font-black text-slate-900 mb-2 text-center">Select Year</h3>
                                <p className="text-slate-500 text-sm text-center mb-6">
                                Practice <span className="font-bold text-slate-900 capitalize">{activeTab}</span> PYQs for <span className="font-bold text-brand-600">{selectedSubject}</span>
                                </p>
                                <div className="flex overflow-x-auto gap-3 pb-6 px-2 hide-scrollbar snap-x">
                                {yearsList.map((year) => (
                                    <button
                                    key={year}
                                    onClick={() => handleYearClick(year)}
                                    className="snap-center shrink-0 w-20 h-14 rounded-2xl bg-slate-50 border border-slate-200 shadow-sm hover:border-brand-500/50 flex items-center justify-center text-lg font-bold text-slate-700 transition-all active:scale-95 active:bg-slate-100"
