import React, { useState, useEffect } from 'react';
import { ArrowLeft, ZoomIn, ZoomOut, CheckCircle } from 'lucide-react';
import { PYQQuestion, Language } from '../types';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface PYQSubjectiveScreenProps {
  subject: string;
  year: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

export const PYQSubjectiveScreen: React.FC<PYQSubjectiveScreenProps> = ({ 
    subject, 
    year, 
    onExit,
    defaultLanguage = 'English' 
}) => {
  const [questions, setQuestions] = useState<PYQQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  const [fontSize, setFontSize] = useState(16);

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const handleAppBack = () => {
    onExit(); 
    return true;
  };

  useBackHandler(handleAppBack);

  useEffect(() => {
    const fetchQuestions = async () => {
        setLoading(true);
        const data = await api.getPYQs(subject, year, 'subjective');
        setQuestions(data);
        setLoading(false);
    };
    if (subject && year) {
        fetchQuestions();
    }
  }, [subject, year]);

  const currentQ = questions[currentIndex];

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      onExit();
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  const getTxt = (en?: string | null, hi?: string | null) => lang === 'hi' ? (hi || en) : en;

  if (loading) {
      return (
        <div className="h-full flex flex-col items-center justify-center bg-white gap-4">
            <div className="w-10 h-10 border-4 border-brand-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-slate-400 font-medium text-sm animate-pulse">Loading Questions...</p>
        </div>
      );
  }

  if (!questions || questions.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-white">
        <p className="text-slate-500 font-medium">No subjective questions found for this year.</p>
        <button onClick={handleAppBack} className="mt-4 px-6 py-2 bg-slate-100 rounded-lg text-sm font-bold text-slate-700 hover:bg-slate-200">Go Back</button>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col bg-white font-sans animate-fade-in text-slate-900">

      {/* 1. Header (Safe Area pt-safe-header) */}
      <div className="px-4 pb-3 pt-safe-header bg-white border-b border-slate-100 flex justify-between items-center sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <button onClick={handleAppBack} className="p-2 -ml-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors">
            <ArrowLeft size={22} />
          </button>
          <div>
            <h2 className="text-lg font-black text-slate-900 leading-none">Learn Subjective</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">{subject} • {year}</p>
          </div>
        </div>

        <div className="flex items-center bg-slate-50 rounded-lg border border-slate-200 p-1">
          <button 
            onClick={() => setFontSize(s => Math.max(12, s - 2))}
            className="p-1.5 text-slate-400 hover:text-brand-600 active:bg-slate-200 rounded-md transition-all"
          >
            <ZoomOut size={16} />
          </button>
          <div className="w-[1px] h-4 bg-slate-200 mx-1"></div>
          <button 
            onClick={() => setFontSize(s => Math.min(24, s + 2))}
            className="p-1.5 text-slate-400 hover:text-brand-600 active:bg-slate-200 rounded-md transition-all"
          >
            <ZoomIn size={16} />
          </button>
        </div>
      </div>

      {/* 2. Top Bar */}
      <div className="px-5 py-3 flex justify-between items-center bg-slate-50 border-b border-slate-100">
        <div className="flex gap-1 overflow-x-auto hide-scrollbar max-w-[200px]">
            {questions.map((_, idx) => (
                <div 
                    key={idx} 
                    className={`h-1.5 rounded-full transition-all duration-300 shrink-0 ${idx === currentIndex ? 'w-6 bg-brand-600' : 'w-1.5 bg-slate-300'}`}
                />
            ))}
        </div>
        <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-white px-3 py-1 rounded-full border border-slate-200 text-[10px] font-bold text-slate-500 shadow-sm shrink-0 hover:bg-slate-50">
            {lang === 'en' ? 'ENG' : 'HIN'}
        </button>
      </div>

      {/* 3. Content Area */}
      <div className="flex-1 overflow-y-auto p-6 pb-32 w-full">

        <div className="mb-8">
            <div className="flex items-center justify-between mb-3">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Question {currentIndex + 1}</span>
                {currentQ.marks && (
                    <span className="bg-brand-50 text-brand-600 px-2 py-1 rounded text-[10px] font-bold border border-brand-200">
                        +{currentQ.marks} Marks
                    </span>
                )}
            </div>
            <h1 
                className="font-bold text-slate-900 leading-snug font-serif break-words"
                style={{ fontSize: `${fontSize + 4}px` }}
            >
                {getTxt(currentQ.question_text_en, currentQ.question_text_hi)}
            </h1>
        </div>

        <div className="relative pl-4 border-l-2 border-green-500">
            <div className="absolute -left-[9px] -top-1 w-4 h-4 bg-green-500 rounded-full flex items-center justify-center text-white ring-4 ring-white">
                <CheckCircle size={10} strokeWidth={3} />
            </div>
            <h3 className="text-green-600 font-bold text-sm uppercase mb-3 ml-2">Solution</h3>
            <div 
                className="text-slate-700 leading-relaxed ml-2 font-serif break-words"
                style={{ fontSize: `${fontSize}px` }}
            >
                {getTxt(currentQ.answer_text_en, currentQ.answer_text_hi) || getTxt(currentQ.solution_short_en, currentQ.solution_short_hi) || "Detailed answer not available."}
            </div>
        </div>

      </div>

      {/* 4. Bottom Navigation - Fixed Safe Area */}
      <div className="fixed bottom-0 w-full bg-white border-t border-slate-100 p-4 pb-safe z-30 shadow-[0_-5px_20px_rgba(0,0,0,0.05)] flex gap-4">
        <button 
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="flex-1 py-3.5 rounded-xl font-bold text-slate-500 bg-slate-50 border border-slate-200 disabled:opacity-50 disabled:cursor-not-allowed transition-colors hover:bg-slate-100"
        >
            Previous
        </button>
        <button 
            onClick={handleNext}
            className="flex-1 py-3.5 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 hover:bg-brand-700 transition-transform active:scale-[0.98]"
        >
            {currentIndex === questions.length - 1 ? 'Finish' : 'Next'}
        </button>
      </div>

    </div>
  );
};

import React, { useState } from 'react';
import { api } from '../services/api';
import { Loader2, ArrowRight, User, MapPin, Phone, Languages, ChevronLeft, ShieldCheck, Sparkles, GraduationCap, Trophy, Target, Atom, PenTool, NotebookText } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useBackHandler } from '../hooks/useBackHandler';

export const LoginScreen = ({ onLoginSuccess }: { onLoginSuccess: (session: any) => void }) => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    fullName: '',
    location: '',
    mobileNumber: '',
    examLanguage: 'Hindi' as 'Hindi' | 'English'
  });

  const handleAppBack = () => {
     if (step > 1) {
         setStep(prev => prev - 1);
         return true;
     }
     return false; 
  };

  useBackHandler(handleAppBack, step > 1);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleNext = () => {
    if (step === 1 && !formData.fullName.trim()) return;
    if (step === 2 && !formData.location.trim()) return;
    if (step === 3 && formData.mobileNumber.length < 10) return;
    setStep(prev => prev + 1);
  };

  const handleSubmit = async () => {
    setError('');
    setLoading(true);

    try {
      const { user, session, error: authError } = await api.registerOrLogin({
          fullName: formData.fullName,
          mobileNumber: formData.mobileNumber,
          location: formData.location,
          examLanguage: formData.examLanguage
      });

      if (authError) throw authError;

      if (session) {
          onLoginSuccess(session);
      }
    } catch (err: any) {
      setError(err.message || "Connection failed. Please check your internet.");
      setLoading(false);
    }
  };

  const variants = {
    enter: (direction: number) => ({
      x: direction > 0 ? 20 : -20,
      opacity: 0,
    }),
    center: {
      x: 0,
      opacity: 1,
    },
    exit: (direction: number) => ({
      x: direction < 0 ? 20 : -20,
      opacity: 0,
    })
  };

  return (
    <div className="h-[100dvh] flex flex-col bg-slate-50 relative overflow-hidden font-sans text-slate-900">

        <div className="absolute inset-0 overflow-hidden pointer-events-none">
            <div className="absolute -top-[10%] -right-[10%] w-[80vw] h-[80vw] bg-gradient-to-br from-brand-100 to-blue-100 rounded-full blur-3xl opacity-50"></div>
            <div className="absolute -bottom-[10%] -left-[10%] w-[70vw] h-[70vw] bg-gradient-to-tr from-purple-100 to-pink-100 rounded-full blur-3xl opacity-50"></div>

            <div className="absolute top-[15%] left-[8%] text-brand-200 opacity-60">
                <Atom size={56} strokeWidth={1.5} />
            </div>
            <div className="absolute top-[12%] right-[10%] text-blue-200 opacity-60">
                <Target size={40} strokeWidth={1.5} />
            </div>
            <div className="absolute bottom-[20%] left-[5%] text-slate-200 opacity-50 transform -rotate-12">
                <NotebookText size={120} strokeWidth={1} />
            </div>
            <div className="absolute bottom-[25%] right-[5%] text-brand-200 opacity-50 transform rotate-12">
                <PenTool size={100} strokeWidth={1} />
            </div>
            <div className="absolute top-[40%] right-[5%] text-purple-200 opacity-50">
                <Trophy size={32} strokeWidth={1.5} />
            </div>
        </div>

        {/* HEADER */}
        <div className="relative z-10 pt-safe-header pb-8 flex flex-col items-center justify-center shrink-0">
            <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center shadow-lg shadow-brand-200 transform -rotate-3 border border-slate-100">
                    <span className="text-slate-900 font-black text-2xl italic font-sans pr-1">R</span>
                </div>
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tighter leading-none">RAFTAAR</h1>
                    <span className="text-[9px] font-bold text-brand-600 uppercase tracking-[0.3em] block mt-1">Test Series App</span>
                </div>
            </div>
        </div>

        {/* MAIN CONTENT */}
        <div className="flex-1 relative z-20 flex flex-col px-8 pb-safe max-w-md mx-auto w-full justify-center">

            <div className="w-full h-1 bg-slate-200 rounded-full mb-8 overflow-hidden shrink-0">
                <motion.div 
                    className="h-full bg-brand-600 rounded-full"
                    initial={{ width: 0 }}
                    animate={{ width: `${(step / 4) * 100}%` }}
                    transition={{ duration: 0.4 }}
                />
            </div>

            <div className="relative min-h-[300px]">
                <AnimatePresence mode='wait' custom={step}>

                    {step === 1 && (
                        <motion.div key="step1" custom={step} variants={variants} initial="enter" animate="center" exit="exit" transition={{ duration: 0.3 }} className="absolute inset-0 flex flex-col">
                            <h2 className="text-3xl font-black text-slate-900 mb-2">Welcome!</h2>
                            <p className="text-slate-500 font-medium mb-8">Enter your name to begin your test series.</p>
                            <div className="relative group">
                                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-brand-600">
                                    <User size={20} />
                                </div>
                                <input 
                                    autoFocus
                                    name="fullName"
                                    type="text" 
                                    placeholder="Enter your name" 
                                    className="w-full bg-white border border-slate-200 shadow-sm rounded-2xl py-4 pl-12 pr-4 text-lg font-bold text-slate-900 placeholder:text-slate-400 outline-none focus:ring-4 focus:ring-brand-500/20 focus:border-brand-500 transition-all"
                                    value={formData.fullName}
                                    onChange={handleChange}
                                    onKeyDown={(e) => e.key === 'Enter' && handleNext()}
                                />
                            </div>
                        </motion.div>
                    )}

                    {step === 2 && (
