                                <div className="relative group">
                                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-brand-600">
                                        <Phone size={20} />
                                    </div>
                                    <span className="absolute left-11 top-1/2 -translate-y-1/2 text-lg font-bold text-slate-400 border-r border-slate-200 pr-2 mr-2">+91</span>
                                    <input 
                                        autoFocus
                                        name="mobileNumber"
                                        type="tel" 
                                        maxLength={10}
