                onTouchStart={onTouchStart}
                onTouchMove={onTouchMove}
                onTouchEnd={onTouchEnd}
            >
                {/* Slider Track */}
                <div 
                    className="flex h-full" 
                    style={{ 
                        transform: `translateX(calc(-${activeSlide * 100}% + ${dragOffset}px))`,
                        transition: isDragging ? 'none' : 'transform 0.5s cubic-bezier(0.2, 0.8, 0.2, 1)'
                    }}
                >
                    {slides.map((slide, idx) => (
                        <div key={idx} className="min-w-full relative h-full flex flex-col justify-end p-6 overflow-hidden select-none">
                            {/* Background & Overlay */}
                            <div className="absolute inset-0 z-0 pointer-events-none">
                                {slide.image ? (
                                    <img src={slide.image} className="w-full h-full object-cover opacity-90" alt="slide" />
                                ) : (
                                    <div className={`w-full h-full ${slide.bg}`}></div>
                                )}
                                <div className={`absolute inset-0 z-10 ${slide.overlay}`}></div>

                                {/* Telegram Pattern */}
                                {slide.isTelegram && (
                                    <div className="absolute inset-0 opacity-10 grid grid-cols-6 gap-4 p-4 transform -rotate-12">
                                        {[...Array(24)].map((_, i) => (
                                            <i key={i} className="fa-brands fa-telegram text-4xl text-white"></i>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Top Right Profile Image */}
                            {(slide as any).profileImg && (
                                <div className="absolute top-4 right-4 z-20 flex flex-col items-end animate-fade-in">
                                    <div className="w-[90px] h-[90px] rounded-full border-4 border-white/20 shadow-2xl overflow-hidden bg-white/5 backdrop-blur-md">
                                        <img src={(slide as any).profileImg} className="w-full h-full object-cover" alt="Profile" />
                                    </div>
                                </div>
                            )}

                            {/* Content */}
                            {slide.isHero ? (
                                <div className="relative z-20 flex flex-col items-center justify-center h-full text-center">
                                    <div className="flex items-center gap-3 mb-3">
                                        <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center shadow-lg transform -rotate-6">
                                            <span className="text-slate-900 font-black text-xl font-sans">R</span>
                                        </div>
                                        <h2 className="text-4xl font-black tracking-tighter text-white drop-shadow-lg">RAFTAAR</h2>
                                    </div>
                                    <div className="flex flex-wrap justify-center gap-2 text-[10px] font-bold text-slate-300 uppercase tracking-widest mb-4">
                                        <span className="bg-white/10 backdrop-blur-sm px-3 py-1.5 rounded-lg border border-white/10">Infinity Practice</span>
                                        <span className="bg-white/10 backdrop-blur-sm px-3 py-1.5 rounded-lg border border-white/10">Live Mock Test</span>
                                    </div>
                                    <button onClick={slide.action} className="bg-white text-slate-900 px-8 py-2.5 rounded-full text-xs font-black shadow-xl hover:scale-105 transition-transform uppercase tracking-widest">
                                        {slide.btn}
                                    </button>
                                </div>
                            ) : (
                                <div className="relative z-20 text-white">
                                    <h2 className="text-2xl font-black mb-2 tracking-tight drop-shadow-md">{slide.title}</h2>
                                    <div className="inline-block bg-white/20 backdrop-blur-sm px-3 py-1 rounded text-[10px] font-bold uppercase tracking-widest mb-3 border border-white/20">
                                        {slide.subtitle}
                                    </div>
                                    <p className="text-xs opacity-90 leading-relaxed mb-4 max-w-[90%] font-medium text-slate-100 line-clamp-2">{slide.desc}</p>

                                    {slide.link ? (
                                        <a href={slide.link} target="_blank" rel="noreferrer" className="inline-block bg-white text-slate-900 px-5 py-2.5 rounded-xl text-[10px] font-bold shadow-md hover:scale-105 transition-transform uppercase tracking-wider">
                                            {slide.btn}
