                                            {slide.btn}
                                        </button>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Dots Indicator */}
                <div className="absolute bottom-4 right-5 z-30 flex gap-1.5">
                    {slides.map((_, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => { setActiveSlide(idx); setIsPaused(true); setTimeout(() => setIsPaused(false), 5000); }}
                            className={`h-1.5 rounded-full transition-all duration-300 cursor-pointer ${activeSlide === idx ? 'w-6 bg-white' : 'w-1.5 bg-white/40'}`}
                        ></div>
                    ))}
                </div>
            </div>
        </div>

        {/* 4-Grid Menu (SQUARE, DARK BLUE DEPTH, LARGER) */}
        <div className="px-5">
            <h3 className="text-slate-500 dark:text-slate-400 font-bold text-xs uppercase tracking-widest mb-4 ml-1">Quick Access</h3>
            <div className="grid grid-cols-2 gap-4">

                {/* Infinity Practice - Deep Blue/Indigo */}
                <div onClick={onOpenInfinity} className="bg-gradient-to-br from-blue-700 via-indigo-800 to-slate-900 p-6 rounded-[2rem] shadow-2xl shadow-blue-900/20 active:scale-95 transition-transform flex flex-col items-center justify-center text-center aspect-square cursor-pointer relative overflow-hidden group border border-white/5">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full blur-3xl -mr-10 -mt-10"></div>
