                             const rank = idx + 1;
                             let rankStyle = "bg-slate-800 border-slate-700 text-slate-400";
                             let icon = null;

                             if (rank === 1) {
                                 rankStyle = "bg-yellow-500/10 border-yellow-500/50 text-yellow-500";
