                                     </div>
                                 </div>
                             );
                         })
                     )}
                 </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Check, FlaskConical, Atom, Calculator, Dna, Languages, BookType } from 'lucide-react';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface InfinityPracticeModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
  onStartSession: (subject: string, chapters: string[]) => void;
  initialSubject?: string | null;
  onUpdateSubject?: (subject: string | null) => void;
  instantOpen?: boolean;
}

const subjectsList = [
  { name: 'Maths', icon: Calculator, color: 'text-sky-500 dark:text-sky-400', bg: 'bg-white dark:bg-slate-900', border: 'border-slate-200 dark:border-slate-800' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-sky-500 dark:text-sky-400', bg: 'bg-white dark:bg-slate-900', border: 'border-slate-200 dark:border-slate-800' },
  { name: 'Physics', icon: Atom, color: 'text-sky-500 dark:text-sky-400', bg: 'bg-white dark:bg-slate-900', border: 'border-slate-200 dark:border-slate-800' },
  { name: 'Biology', icon: Dna, color: 'text-sky-500 dark:text-sky-400', bg: 'bg-white dark:bg-slate-900', border: 'border-slate-200 dark:border-slate-800' },
  { name: 'Hindi', icon: Languages, color: 'text-sky-500 dark:text-sky-400', bg: 'bg-white dark:bg-slate-900', border: 'border-slate-200 dark:border-slate-800' },
  { name: 'English', icon: BookType, color: 'text-sky-500 dark:text-sky-400', bg: 'bg-white dark:bg-slate-900', border: 'border-slate-200 dark:border-slate-800' },
];

export const InfinityPracticeModal: React.FC<InfinityPracticeModalProps> = ({ 
  isOpen, 
  onClose, 
  userId, 
  onStartSession,
  initialSubject,
  onUpdateSubject,
  instantOpen = false
}) => {
  // We removed local 'step' state. Step is now derived from selectedSubject.
  // If subject is selected -> Step 2. Else -> Step 1.
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject || null);
  const step = selectedSubject ? 2 : 1;

  const [chapters, setChapters] = useState<{ en: string, hi: string, count: number }[]>([]);
  const [selectedChapters, setSelectedChapters] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  // Sync internal state with props (URL params)
  useEffect(() => {
    if (isOpen) {
        setSelectedSubject(initialSubject || null);
        // Reset chapters if going back to step 1
        if (!initialSubject) {
            setSelectedChapters([]);
        }
    }
  }, [isOpen, initialSubject]);

  // Stack Navigation Logic for Hardware Back Button
  const handleAppBack = () => {
    if (step === 2) {
      // Go back to Step 1
      setSelectedSubject(null);
      if (onUpdateSubject) onUpdateSubject(null); // Update URL
      return true; // Trap
    } else {
      // Exit Modal
      onClose(); 
      return true; // Trap
    }
  };

  useBackHandler(handleAppBack, isOpen);

  useEffect(() => {
    if (selectedSubject) {
      setLoading(true);
      api.getChapterStats(selectedSubject).then(data => {
        setChapters(data);
        // Pre-select first 3 for convenience, or empty
        setSelectedChapters(data.slice(0, 3).map(c => c.en));
        setLoading(false);
      });
    }
  }, [selectedSubject]);

  const handleSubjectSelect = (subject: string) => {
    setSelectedSubject(subject);
    if (onUpdateSubject) onUpdateSubject(subject);
  };

  const toggleChapter = (chapterName: string) => {
    setSelectedChapters(prev => 
      prev.includes(chapterName) 
        ? prev.filter(c => c !== chapterName) 
        : [...prev, chapterName]
    );
  };

  const handleStart = async () => {
    if (!selectedSubject) return;
    if (selectedChapters.length < 2) {
        alert("Minimum 2 chapters required to start.");
        return;
    }
    setCreating(true);
    // Simulating API creation delay if needed
    const sessionId = await api.createPracticeSession(userId, selectedSubject, selectedChapters);
    setCreating(false);
    onStartSession(selectedSubject, selectedChapters);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div 
            initial={{ opacity: instantOpen ? 0.5 : 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black z-40"
          />

          <motion.div
            initial={{ x: instantOpen ? 0 : "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            className="fixed inset-y-0 right-0 w-full max-w-md bg-white dark:bg-slate-950 z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans text-slate-900 dark:text-white"
          >
            <div className="bg-white dark:bg-slate-950 shadow-sm z-20 border-b border-slate-100 dark:border-slate-800 shrink-0 sticky top-0">
                <div className="pt-safe-header pb-4 px-5 flex items-center gap-3">
