                </div>
            </div>
        </div>

        {/* Featured Series */}
        <div className="px-5">
            <h3 className="text-slate-500 dark:text-slate-400 font-bold text-[10px] uppercase tracking-widest mb-3 ml-1">Featured Series</h3>
