                        ></div>
                    ))}
                </div>
            </div>
        </div>

        {/* 4-Grid Menu (Compact) */}
        <div className="px-5">
            <h3 className="text-slate-500 dark:text-slate-400 font-bold text-[10px] uppercase tracking-widest mb-3 ml-1">Quick Access</h3>
            <div className="grid grid-cols-2 gap-3">

